import React, { useState, useEffect } from 'react';

const defaultCategories = [
  { id: 'btech', label: 'B.Tech', badge: 'DEGREE', color: 'border-blue-500', bgColor: 'bg-blue-500', lightBg: 'bg-blue-50', programs: ['Information & Communication Technology (ICT)', 'Civil Engineering', 'Automobile Engineering', 'Mechanical Engineering', 'Metallurgical Engineering', 'Electrical Engineering', 'Electronics & Communication Engineering', 'Computer Engineering', 'Cyber Security', 'Information Technology', 'Computer Science Engineering', 'Aircraft Maintenance Engineering', 'Aeronautical Engineering', 'Aerospace Engineering', 'Defence Aerospace Engineering'] },
  { id: 'btech-dtd', label: 'B.Tech (D to D)', badge: 'LATERAL', color: 'border-amber-700', bgColor: 'bg-amber-700', lightBg: 'bg-amber-50', programs: ['Information & Communication Technology (ICT)', 'Civil Engineering', 'Automobile Engineering', 'Mechanical Engineering', 'Metallurgical Engineering', 'Electrical Engineering', 'Electronics & Communication Engineering', 'Computer Engineering', 'Cyber Security', 'Information Technology', 'Computer Science Engineering'] },
  { id: 'diploma', label: 'Diploma', badge: 'TECHNICAL', color: 'border-orange-500', bgColor: 'bg-orange-500', lightBg: 'bg-orange-50', programs: ['Information & Communication Technology (ICT)', 'Civil Engineering', 'Automobile Engineering', 'Mechanical Engineering', 'Computer Engineering', 'Electrical Engineering', 'Electronics & Communication Engineering'] },
  { id: 'mtech', label: 'M.Tech', badge: 'MASTERS', color: 'border-red-600', bgColor: 'bg-red-600', lightBg: 'bg-red-50', programs: ['CAD / CAM (Mechanical Engr.)', 'Construction Project Management (Civil Engg.)', 'Digital Communication (EC Engg.)', 'Electrical Power System', 'Industrial Metallurgy', 'Structural Engineering (Civil Engg.)', 'Data Science (Computer)', 'Cyber Security'] },
  { id: 'bdes', label: 'B.Des', badge: 'DESIGN', color: 'border-yellow-500', bgColor: 'bg-yellow-500', lightBg: 'bg-yellow-50', programs: ['Product Design', 'Interior Design', 'Fashion Design', 'Communication Design - (Graphic Design)'] },
  { id: 'mdes', label: 'M.Des', badge: 'MASTERS', color: 'border-teal-600', bgColor: 'bg-teal-600', lightBg: 'bg-teal-50', programs: ['Fashion Design', 'Interior Design', 'UI-UX Design'] },
  { id: 'bsc', label: 'B.Sc', badge: 'SCIENCE', color: 'border-blue-400', bgColor: 'bg-blue-400', lightBg: 'bg-blue-50', programs: ['Data Science', 'Computer Application (CA) & (IT)', 'Clinical Research (Hons)', 'Mathematics (Hons)', 'Physics (Hons)', 'Chemistry (Hons)', 'Cyber Security (Hons)', 'Microbiology (Hons)', 'Computer Science (AI & ML)'] },
  { id: 'msc', label: 'M.Sc', badge: 'MASTERS', color: 'border-indigo-600', bgColor: 'bg-indigo-600', lightBg: 'bg-indigo-50', programs: ['Information Technology (IT)', 'Clinical Research', 'Mathematics', 'Physics', 'Chemistry', 'Cyber Security', 'Microbiology'] },
  { id: 'mba-avia', label: 'MBA/BBA', badge: 'BUSINESS', color: 'border-purple-600', bgColor: 'bg-purple-600', lightBg: 'bg-purple-50', programs: ['Aviation Management', 'BBA', 'Marketing', 'Finance', 'Human Resource'] },
  { id: 'bca', label: 'BCA', badge: 'COMPUTER', color: 'border-cyan-500', bgColor: 'bg-cyan-500', lightBg: 'bg-cyan-50', programs: ['BCA'] },
  { id: 'mca', label: 'MCA', badge: 'POST-GRAD', color: 'border-rose-500', bgColor: 'bg-rose-500', lightBg: 'bg-rose-50', programs: ['MCA'] }
];

export default function AdminCategories({ confirmDelete, CenterModal }) {
  const [categories, setCategories] = useState([]);
  const [catForm, setCatForm] = useState({ id: '', label: '', badge: '', color: 'border-blue-500', bgColor: 'bg-blue-500', lightBg: 'bg-blue-50', programs: '' });

  // Navigation State
  const [selectedCategoryNav, setSelectedCategoryNav] = useState(null);
  const [searchQuery, setSearchQuery] = useState('');

  // Program Details Editing
  const [programData, setProgramData] = useState({});
  const [selectedProgramEdit, setSelectedProgramEdit] = useState('');
  const [jsonInput, setJsonInput] = useState('');
  const [jsonError, setJsonError] = useState('');
  const [newCourseName, setNewCourseName] = useState('');

  useEffect(() => {
    const loadCategories = () => {
      const storedCat = localStorage.getItem('indus_categories');
      setCategories(storedCat ? JSON.parse(storedCat) : defaultCategories);
    };

    loadCategories();
    const storedProg = localStorage.getItem('indus_programData');
    setProgramData(storedProg ? JSON.parse(storedProg) : {});

    window.addEventListener('storage', loadCategories);
    return () => window.removeEventListener('storage', loadCategories);
  }, []);

  const saveCats = (data) => {
    setCategories(data);
    localStorage.setItem('indus_categories', JSON.stringify(data));
  };
  const saveProgData = (data) => {
    setProgramData(data);
    localStorage.setItem('indus_programData', JSON.stringify(data));
  };

  const saveCategory = (e) => {
    e.preventDefault();
    const id = catForm.id || catForm.label.toLowerCase().replace(/\s+/g, '-');
    const existing = categories.findIndex(c => c.id === id);
    const newCat = {
      ...catForm,
      id,
      programs: typeof catForm.programs === 'string' ? catForm.programs.split(',').map(s => s.trim()).filter(p => p) : catForm.programs
    };

    if (existing >= 0) {
      const updated = [...categories];
      updated[existing] = newCat;
      saveCats(updated);
    } else {
      saveCats([...categories, newCat]);
    }
    setCatForm({ id: '', label: '', badge: '', color: 'border-blue-500', bgColor: 'bg-blue-500', lightBg: 'bg-blue-50', programs: '' });
  };

  const handleProgramSelect = (prog) => {
    setSelectedProgramEdit(prog);
    const data = programData[prog] || { 'CURRICULUM & LEARNING': { sections: [{ title: 'Overview', items: ['Point 1'] }] } };
    setJsonInput(JSON.stringify(data, null, 2));
    setJsonError('');
  };

  const handleJsonSave = () => {
    try {
      const parsed = JSON.parse(jsonInput);
      setJsonError('');
      saveProgData({ ...programData, [selectedProgramEdit]: parsed });
      alert('Program details updated successfully!');
      setSelectedProgramEdit('');
    } catch(err) {
      setJsonError('Invalid JSON format: ' + err.message);
    }
  };

  const handleAddCourse = () => {
    if (!newCourseName.trim()) return;
    const updatedCats = categories.map(c => {
      if (c.id === selectedCategoryNav.id) {
        return { ...c, programs: [...c.programs, newCourseName.trim()] };
      }
      return c;
    });
    saveCats(updatedCats);
    setSelectedCategoryNav(updatedCats.find(c => c.id === selectedCategoryNav.id));
    setNewCourseName('');
    alert('New course added to track!');
  };

  const handleRemoveCourse = (courseName) => {
    if (!window.confirm(`Delete course "${courseName}"?`)) return;
    const updatedCats = categories.map(c => {
      if (c.id === selectedCategoryNav.id) {
        return { ...c, programs: c.programs.filter(p => p !== courseName) };
      }
      return c;
    });
    saveCats(updatedCats);
    setSelectedCategoryNav(updatedCats.find(c => c.id === selectedCategoryNav.id));
  };

  const [activeMetadataTab, setActiveMetadataTab] = useState('CURRICULUM & LEARNING');

  const metadataTabs = [
    { id: 'CURRICULUM & LEARNING', label: 'Curriculum' },
    { id: 'INDUSTRY EXPOSURE', label: 'Industry' },
    { id: 'CAREER PROSPECTS', label: 'Career' },
    { id: 'WHY CHOOSE US', label: 'Choice' },
    { id: 'ELIGIBILITY', label: 'Eligibility' },
    { id: 'ADMISSION', label: 'Admission' },
    { id: 'FEES STRUCTURE', label: 'Fees' }
  ];

  const updateMethodology = (newContent) => {
    setJsonInput(JSON.stringify(newContent, null, 2));
  };

  const addSection = () => {
    const current = JSON.parse(jsonInput);
    const updated = { ...current };
    if (!updated[activeMetadataTab]) updated[activeMetadataTab] = { sections: [] };
    updated[activeMetadataTab].sections.push({ title: 'New Section', items: ['New Point'] });
    updateMethodology(updated);
  };

  const updateSectionTitle = (sIdx, title) => {
    const updated = JSON.parse(jsonInput);
    updated[activeMetadataTab].sections[sIdx].title = title;
    updateMethodology(updated);
  };

  const addPoint = (sIdx) => {
    const updated = JSON.parse(jsonInput);
    updated[activeMetadataTab].sections[sIdx].items.push('New Point');
    updateMethodology(updated);
  };

  const updatePoint = (sIdx, pIdx, val) => {
    const updated = JSON.parse(jsonInput);
    updated[activeMetadataTab].sections[sIdx].items[pIdx] = val;
    updateMethodology(updated);
  };

  const removePoint = (sIdx, pIdx) => {
    const updated = JSON.parse(jsonInput);
    updated[activeMetadataTab].sections[sIdx].items.splice(pIdx, 1);
    updateMethodology(updated);
  };

  const removeSection = (sIdx) => {
    const updated = JSON.parse(jsonInput);
    updated[activeMetadataTab].sections.splice(sIdx, 1);
    updateMethodology(updated);
  };

  if (selectedProgramEdit) {
    const allData = JSON.parse(jsonInput);
    const activeData = allData[activeMetadataTab] || { sections: [] };

    return (
      <div className="space-y-8 fade-in">
        <div className="flex flex-col lg:flex-row lg:items-center justify-between gap-6 bg-white p-8 rounded-[2.5rem] border border-slate-100 shadow-sm">
           <div className="flex items-center gap-6">
              <button 
                onClick={() => setSelectedProgramEdit('')}
                className="w-12 h-12 rounded-xl bg-slate-50 flex items-center justify-center text-slate-400 hover:text-blue-600 hover:bg-blue-50 transition-all border border-slate-100"
              >
                <svg className="w-6 h-6" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="3" d="M15 19l-7-7 7-7" /></svg>
              </button>
              <div>
                 <span className="text-[10px] font-black uppercase text-slate-400 tracking-[0.2em] mb-1 block">Course Spectrum Manager</span>
                 <h4 className="text-3xl font-black text-slate-900 leading-none">{selectedProgramEdit}</h4>
              </div>
           </div>

           <div className="flex gap-2 bg-slate-50 p-2 rounded-2xl overflow-x-auto max-w-full no-scrollbar">
              {metadataTabs.map(tab => (
                 <button 
                   key={tab.id}
                   onClick={() => setActiveMetadataTab(tab.id)}
                   className={`px-5 py-2.5 rounded-xl text-[10px] font-black uppercase tracking-widest transition-all whitespace-nowrap ${
                     activeMetadataTab === tab.id 
                     ? 'bg-slate-900 text-white shadow-lg shadow-slate-900/10' 
                     : 'text-slate-400 hover:text-slate-600'
                   }`}
                 >
                   {tab.label}
                 </button>
              ))}
           </div>

           <button onClick={handleJsonSave} className="bg-blue-600 text-white font-black px-10 py-4 rounded-xl hover:bg-blue-700 transition-all shadow-xl shadow-blue-600/20">Save Spectrum</button>
        </div>

        <div className="bg-[#f2f0ee] p-10 rounded-[3rem] border border-slate-200">
           <div className="space-y-10">
              <div className="flex items-center gap-4 mb-6">
                 <div className="h-0.5 flex-1 bg-slate-200"></div>
                 <span className="text-[10px] font-black text-slate-400 uppercase tracking-widest bg-slate-200/50 px-4 py-1 rounded-full">Active Area: {activeMetadataTab}</span>
                 <div className="h-0.5 flex-1 bg-slate-200"></div>
              </div>

              {activeData.sections.length > 0 ? activeData.sections.map((section, sIdx) => (
                <div key={sIdx} className="bg-white p-10 rounded-[2.5rem] shadow-sm border border-slate-100 relative group">
                   <button 
                     onClick={() => removeSection(sIdx)}
                     className="absolute top-8 right-8 text-slate-200 hover:text-red-500 transition-colors"
                   >
                     <svg className="w-6 h-6" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M19 7l-.867 12.142A2 2 0 0116.138 21H7.862a2 2 0 01-1.995-1.858L5 7m5 4v6m4-6v6m1-10V4a1 1 0 00-1-1h-4a1 1 0 00-1 1v3M4 7h16" /></svg>
                   </button>

                   <div className="mb-8">
                      <label className="block text-[10px] font-black text-blue-600 uppercase tracking-widest mb-3">Section Title</label>
                      <input 
                        type="text" 
                        value={section.title}
                        onChange={(e) => updateSectionTitle(sIdx, e.target.value)}
                        className="w-full text-2xl font-black text-slate-900 border-b-2 border-slate-100 focus:border-blue-500 outline-none pb-2 transition-colors focus:bg-slate-50/50"
                      />
                   </div>

                   <div className="space-y-4">
                      <label className="block text-[10px] font-black text-slate-400 uppercase tracking-widest mb-2">Curriculum Points</label>
                      {section.items.map((item, pIdx) => (
                        <div key={pIdx} className="flex gap-4 items-center group/p">
                           <div className="w-2 h-2 rounded-full bg-blue-500 shrink-0"></div>
                           <input 
                             type="text" 
                             value={item}
                             onChange={(e) => updatePoint(sIdx, pIdx, e.target.value)}
                             className="flex-1 bg-slate-50 border border-transparent focus:border-blue-500/20 px-4 py-3 rounded-xl font-bold text-slate-700 outline-none focus:bg-white transition-all"
                           />
                           <button 
                             onClick={() => removePoint(sIdx, pIdx)}
                             className="text-slate-200 hover:text-red-500 transition-colors opacity-0 group-hover/p:opacity-100"
                           >
                             <svg className="w-5 h-5" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M6 18L18 6M6 6l12 12" /></svg>
                           </button>
                        </div>
                      ))}
                      <button 
                        onClick={() => addPoint(sIdx)}
                        className="mt-4 text-[11px] font-black text-blue-600 hover:text-blue-700 flex items-center gap-2 uppercase tracking-widest bg-blue-50 px-6 py-3 rounded-xl transition-colors"
                      >
                        + Add Point
                      </button>
                   </div>
                </div>
              )) : (
                <div className="bg-white/50 border-2 border-dashed border-slate-300 p-20 rounded-[2.5rem] text-center">
                   <p className="text-slate-400 font-bold italic mb-0">No sections added yet for "{metadataTabs.find(t => t.id === activeMetadataTab)?.label}". Click below to define your first section.</p>
                </div>
              )}

              <button 
                onClick={addSection}
                className="w-full border-2 border-dashed border-slate-300 p-10 rounded-[2.5rem] text-slate-400 font-black flex items-center justify-center gap-4 hover:border-blue-500 hover:text-blue-600 hover:bg-white transition-all uppercase tracking-widest"
              >
                <svg className="w-8 h-8" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="3" d="M12 4v16m8-8H4" /></svg>
                Add Content Section for {metadataTabs.find(t => t.id === activeMetadataTab)?.label}
              </button>
           </div>
        </div>
      </div>
    );
  }

  if (selectedCategoryNav) {
    return (
      <div className="space-y-8 fade-in">
        <div className="flex flex-col md:flex-row md:items-center justify-between gap-6">
           <div className="flex items-center gap-6">
              <button 
                onClick={() => setSelectedCategoryNav(null)}
                className="group flex items-center px-6 py-3 bg-white border border-slate-200 rounded-xl font-bold text-slate-600 hover:bg-slate-50 transition-all"
              >
                <svg className="w-4 h-4 mr-2 group-hover:-translate-x-1 transition-transform" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="3" d="M15 19l-7-7 7-7" /></svg>
                BACK TO CATEGORIES
              </button>
              <h2 className="text-4xl font-black text-slate-900 tracking-tight">{selectedCategoryNav.label} Courses</h2>
           </div>
           <div className="relative">
              <input 
                type="text" 
                placeholder="Search courses..." 
                value={searchQuery}
                onChange={e => setSearchQuery(e.target.value)}
                className="bg-white border border-slate-200 px-6 py-3 rounded-xl outline-none font-bold text-sm w-[300px] shadow-sm focus:border-brand-brown transition-colors"
              />
           </div>
        </div>

        <div className="bg-[#f2f0ee] p-10 rounded-[3rem] shadow-sm border border-slate-200">
          <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-6">
             {/* Add New Course Card */}
             <div className="bg-slate-50 p-8 rounded-[2.5rem] border-2 border-dashed border-slate-300 flex flex-col justify-center items-center group hover:bg-white hover:border-blue-500/30 transition-all">
                <input 
                  type="text" 
                  placeholder="Course Name..." 
                  value={newCourseName}
                  onChange={e => setNewCourseName(e.target.value)}
                  className="w-full bg-white border border-slate-200 rounded-xl px-4 py-3 mb-4 font-bold text-sm outline-none focus:ring-2 ring-blue-500/20"
                />
                <button 
                  onClick={handleAddCourse}
                  className="w-full bg-slate-800 text-white font-black py-3 rounded-xl hover:bg-slate-900 active:scale-95 transition-all shadow-lg shadow-slate-800/10"
                >
                  + ADD NEW COURSE
                </button>
             </div>

             {selectedCategoryNav.programs
              .filter(p => p.toLowerCase().includes(searchQuery.toLowerCase()))
              .map((prog, idx) => (
                <div 
                  key={idx} 
                  className="bg-white p-8 rounded-[2.5rem] shadow-sm border border-slate-100 hover:border-blue-500/20 hover:shadow-xl transition-all group relative overflow-hidden"
                >
                  <div onClick={() => handleProgramSelect(prog)} className="cursor-pointer relative z-10 flex items-center justify-between">
                     <div>
                        <div className="text-[10px] font-black text-slate-300 tracking-widest uppercase mb-1">CONFIGURE COURSE</div>
                        <h4 className="text-xl font-black text-slate-800 group-hover:text-blue-600 transition-colors">{prog}</h4>
                     </div>
                     <div className="w-10 h-10 rounded-full bg-slate-50 flex items-center justify-center text-slate-300 group-hover:bg-blue-500/10 group-hover:text-blue-600 transition-all">
                        <svg className="w-5 h-5" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="3" d="M9 5l7 7-7 7" /></svg>
                     </div>
                  </div>

                  {/* Remove button */}
                  <button 
                    onClick={(e) => { e.stopPropagation(); handleRemoveCourse(prog); }}
                    className="absolute top-4 right-4 p-2 text-slate-200 hover:text-red-400 transition-colors opacity-0 group-hover:opacity-100"
                  >
                    <svg className="w-4 h-4" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M6 18L18 6M6 6l12 12" /></svg>
                  </button>

                  <div className="absolute -bottom-8 -right-8 w-24 h-24 bg-slate-50 rounded-full opacity-0 group-hover:opacity-100 transition-opacity pointer-events-none"></div>
                </div>
             ))}
          </div>
        </div>
      </div>
    );
  }

  return (
    <div className="space-y-12 fade-in">
      {/* Category Management */}
      <div className="grid grid-cols-1 lg:grid-cols-12 gap-10">
        <div className="lg:col-span-4">
           <div className="bg-[#f2f0ee] p-8 rounded-[2rem] shadow-sm border border-slate-200/50">
             <h3 className="text-2xl font-black mb-8 text-slate-800 border-l-4 border-slate-400 pl-4">{catForm.id ? 'Edit Category Meta' : 'New Category '}</h3>
             <form onSubmit={saveCategory} className="space-y-6">
                <div>
                  <label className="block text-[10px] font-black uppercase text-slate-400 mb-2">Category Label (e.g. B.Tech)</label>
                  <input required type="text" value={catForm.label} onChange={e => setCatForm({...catForm, label: e.target.value})} className="w-full bg-slate-50 p-4 rounded-xl outline-none font-bold focus:bg-white border border-transparent focus:border-blue-500/20" />
                </div>
                <div>
                  <label className="block text-[10px] font-black uppercase text-slate-400 mb-2">Badge Text (e.g. DEGREE)</label>
                  <input required type="text" value={catForm.badge} onChange={e => setCatForm({...catForm, badge: e.target.value})} className="w-full bg-slate-50 p-4 rounded-xl outline-none font-bold uppercase focus:bg-white border border-transparent focus:border-blue-500/20" />
                </div>
                <div>
                  <label className="block text-[10px] font-black uppercase text-slate-400 mb-2">Programs (comma separated list)</label>
                  <textarea placeholder="Civil, Mechanical..." value={typeof catForm.programs === 'string' ? catForm.programs : catForm.programs.join(', ')} onChange={e => setCatForm({...catForm, programs: e.target.value})} className="w-full bg-slate-50 p-4 rounded-xl outline-none font-bold min-h-[120px] focus:bg-white border border-transparent focus:border-blue-500/20"></textarea>
                </div>
                <div className="flex gap-3">
                  <button type="submit" className="flex-1 bg-slate-800 text-white font-black py-4 rounded-xl hover:bg-slate-900 transition-all shadow-md active:scale-95">Save Track</button>
                  {catForm.id && <button type="button" onClick={() => setCatForm({ id: '', label: '', badge: '', color: 'border-blue-500', bgColor: 'bg-blue-500', lightBg: 'bg-blue-50', programs: '' })} className="px-6 bg-slate-100 rounded-xl font-bold text-slate-500">Cancel</button>}
                </div>
             </form>
           </div>
        </div>

        <div className="lg:col-span-8 bg-[#f2f0ee] p-8 rounded-[2.5rem] shadow-sm border border-slate-200">
           <h3 className="text-xl font-black text-slate-800 mb-8 uppercase tracking-[0.2em]">System Categories</h3>
           <div className="grid grid-cols-1 md:grid-cols-2 gap-6 pb-4">
             {categories.map((cat) => (
               <div key={cat.id} className="bg-white p-8 rounded-[2.5rem] shadow-sm border border-slate-100 relative group hover:shadow-xl hover:shadow-slate-200/20 transition-all duration-500 border-t-4 hover:border-t-slate-800 overflow-hidden">
                  {/* Background Decoration */}
                  <div className="absolute -right-8 -top-8 w-24 h-24 bg-slate-50 rounded-full opacity-0 group-hover:opacity-100 transition-opacity duration-700"></div>

                  <div className="relative z-10">
                    <div className="text-[10px] font-black text-slate-300 tracking-[0.2em] mb-3 uppercase">{cat.badge} • TRACK</div>
                    <h4 className="text-3xl font-black text-slate-900 mb-6 tracking-tight">{cat.label}</h4>

                    <div className="flex flex-wrap items-center gap-3">
                       <button 
                         onClick={() => setSelectedCategoryNav(cat)} 
                         className="flex-1 min-w-[140px] px-6 py-3.5 bg-slate-900 text-white text-[11px] font-black rounded-xl hover:bg-blue-600 transition-all uppercase tracking-widest shadow-lg shadow-slate-900/10 hover:shadow-blue-600/20 flex items-center justify-center gap-2"
                       >
                         Manage Courses
                         <svg className="w-3.5 h-3.5" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="3" d="M13 7l5 5m0 0l-5 5m5-5H6" /></svg>
                       </button>
                       <button 
                         onClick={() => setCatForm(cat)} 
                         className="px-5 py-3.5 bg-slate-50 text-slate-600 text-[11px] font-black rounded-xl hover:bg-slate-100 transition-colors uppercase tracking-widest border border-slate-100"
                       >
                         Meta
                       </button>
                       <button 
                         onClick={() => confirmDelete('category', cat.id, cat.label)} 
                         className="p-3.5 text-slate-300 hover:text-red-500 hover:bg-red-50 transition-all rounded-xl"
                       >
                         <svg className="w-5 h-5" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M19 7l-.867 12.142A2 2 0 0116.138 21H7.862a2 2 0 01-1.995-1.858L5 7m5 4v6m4-6v6m1-10V4a1 1 0 00-1-1h-4a1 1 0 00-1 1v3M4 7h16" /></svg>
                       </button>
                    </div>
                    <p className="mt-8 text-[11px] font-bold text-slate-400 italic flex items-center gap-2">
                      <span className="w-1.5 h-1.5 rounded-full bg-slate-200"></span>
                      Contains {cat.programs.length} specialized programs
                    </p>
                  </div>
               </div>
             ))}
           </div>
        </div>
      </div>
    </div>
  );
}
